// Note: Granular and caustic sound synthesis.
//       Adapted for Desktop GLSL Audio.
// =========================================================================

#define PI2_LOCAL 6.28318530718
#define M_C 261.625565
#define PW 1.05946309436

// Hash 3D per la generazione di numeri casuali (Dave Hoskins)
vec3 hash31(float p) {
   vec3 p3 = fract(vec3(p) * vec3(.1031, .1030, .0973));
   p3 += dot(p3, p3.yzx + 19.19);
   return fract((p3.xxy + p3.yzz) * p3.zyx); 
}

// Funzione generatrice della nota (Sintesi FM + Inviluppo)
float X (
    float time,
    float phase,
    float octave, 
    float note, 
    float attack,
    float sustain,
    float release,
    float nl
) {
    float phi = phase * PI2_LOCAL;
    // Calcolo della frequenza basato sul temperamento equabile
    float w = M_C * PI2_LOCAL * exp2(octave) * pow(PW, note);

    // Inviluppo ADSR semplificato
    float envelope = smoothstep(0., attack, time - phase) * smoothstep(release, 0., time - phase - attack - sustain);

    // Sintesi FM: due oscillatori dove la fase è modulata da un altro coseno
    float wave1 = cos(w * time - phi + 50. * cos(0.001 * nl * w * time));
    float wave2 = cos(0.25 * w * time - phi + 30. * cos(0.002 * nl * w * time));

    return (wave1 + wave2) * envelope;
}

// -------------------------------------------------------------------------
// MAIN SOUND
// -------------------------------------------------------------------------

vec2 mainSound( in int samp, float t ) {
    float a = 0.;
    #define N_VOICES 15.

    // Iterazione per generare polifonia e texture
    for (float i = 0.; i < N_VOICES; i++) {
        float time_idx = 0.;
        float note = 0.;
        float root = 0.;
        float octave = 1.0;
        vec3 h;
        float d = 1.0;

        // Logica temporale per creare ritmi frattali
        time_idx = floor(t);
        h = hash31(time_idx);
        root = floor(h.x * 12.) - 12.;
        h = hash31(time_idx + i);

        // Suddivisione ritmica casuale (stocastica)
        if (h.x > 0.4) {
            d *= 0.5;
            time_idx = floor(t);
            h = hash31(2. * time_idx + i * 100.);
            if (h.x > 0.6) {
                d *= 0.5;
                time_idx = floor(t * 2.) / 2.;
                h = hash31(20. * time_idx + i * 120.);
            }
        }

        // Selezione della nota nella scala
        note = 2. * floor(h.z * 6.) - 4.;

        // Somma delle voci
        a += 0.5 * X(t, time_idx, octave, root + note, 0.01 * d, 0.9 * d, 0.1 * d, 0.2 * h.x);
    }

    // Normalizzazione e output stereo (mono in questo caso, bilanciato su vec2)
    vec2 audio = vec2(a) / N_VOICES;

    // Fade-in iniziale e limiter finale
    return clamp(audio * smoothstep(0.0, 1.0, t), -1.0, 1.0);
}
// SOUND_END
//SOUND_END

vec3 palette(float d){
	return mix(vec3(0.2,0.7,0.9),vec3(1.,0.,1.),d);
}

vec2 rotate(vec2 p,float a){
	float c = cos(a);
    float s = sin(a);
    return p*mat2(c,s,-s,c);
}

float map(vec3 p){
    for( int i = 0; i<8; ++i){
        float t = iTime*0.2;
        p.xz =rotate(p.xz,t);
        p.xy =rotate(p.xy,t*1.89);
        p.xz = abs(p.xz);
        p.xz-=.5;
	}
	return dot(sign(p),p)/5.;
}

vec4 rm (vec3 ro, vec3 rd){
    float t = 0.;
    vec3 col = vec3(0.);
    float d;
    for(float i =0.; i<64.; i++){
		vec3 p = ro + rd*t;
        d = map(p)*.5;
        if(d<0.02){
            break;
        }
        if(d>100.){
        	break;
        }
        //col+=vec3(0.6,0.8,0.8)/(400.*(d));
        col+=palette(length(p)*.1)/(400.*(d));
        t+=d;
    }
    return vec4(col,1./(d*100.));
}
void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    vec2 uv = (fragCoord-(iResolution.xy/2.))/iResolution.x;
	vec3 ro = vec3(0.,0.,-50.);
    ro.xz = rotate(ro.xz,iTime);
    vec3 cf = normalize(-ro);
    vec3 cs = normalize(cross(cf,vec3(0.,1.,0.)));
    vec3 cu = normalize(cross(cf,cs));

    vec3 uuv = ro+cf*3. + uv.x*cs + uv.y*cu;

    vec3 rd = normalize(uuv-ro);

    vec4 col = rm(ro,rd);


    fragColor = col;
}

